<?php class Model_Mapper_FactorConversion{	private static $_instance;		public static function getInstance()	{		if(null == self::$_instance)		{			self::$_instance = new self;		}		return self::$_instance;	}	private function __construct(){}	public function getFactorConversion($id)	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchRow($db->select()	->from(array('f' => 'tbl_factorConversion'))											->where('f.id_factorConversion = ?',$id)											->join(array('i' => 'tbl_indicador'),'i.tbl_factorConversion_id_factorConversion = f.id_factorConversion'));	}		public function getFactoresDeConversion()	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchAll($db->select()	->from(array('f'=>'tbl_factorConversion'))											->join(array('i' => 'tbl_indicador'),'i.tbl_factorConversion_id_factorConversion = f.id_factorConversion')											->order('i.orden_indicador ASC'));	}		public function getIndicadorByFactorConversion($idFactor)	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchRow($db->select()->from('tbl_indicador','id_indicador')->where('tbl_factor_id_factor = ?',$idFactor));	}		public function getFactorConversionByIndicador($idIndicador)	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchRow($db->select()->from('tbl_indicador','tbl_factorConversion_id_factorConversion')->where('id_indicador = ?',$idIndicador));	}		public function getIdFactorConversionByFicha($ficha)	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchRow($db->select()	->from(('tbl_factorConversion'),'id_factorConversion')											->where('ficha_factorConversion = ?',$ficha));	}		public function updateFactorConversion($fila)	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->update('tbl_factorConversion',$fila,$db->quoteInto('id_factorConversion=?',$fila['id_factorConversion']));	}		public function insertFactorConversion($fila)	{		$db = Zend_Db_Table::getDefaultAdapter();		$db->insert('tbl_factorConversion',$fila);		return $db->lastInsertId();	}}